int alloc_node(struct tree *t, int val)
{
    struct node *n;
    int err;

    n = kmalloc(sizeof(*n), GFP_KERNEL);
    if (!n)
        return -ENOMEM;
    n->val = val;
    n->left = NULL;
    n->right = NULL;
    err = tree_insert(t, n);
    if (err)
        goto out_free;
    return 0;
out_free:
    kfree(n);
    return err;
}
